*/
// end BLOCK 2-----------------------
	},

	_createTaskMenu: function(page_id){
		return this._loadPageTaskViewsMenu(page_id);
	},

	_getMenuItemByPageId: function(page_id, page_array){
		for (var i=0; i < page_array.length; i++) {
			var menuItem = page_array[i];
			if (menuItem.id === page_id) {
				menuItem.disabled = true;
				return menuItem;
			}
		}
/*				var item;
		for (item in pageTaskViewsMenu){
			var menuItem = pageTaskViewsMenu[item];
			if(menuItem.id == page_id){
				// disable  the menu item for the current page
				menuItem.disabled = true;
			}
		}
		*/
	},

